import play.api.db._
import slick.driver.JdbcProfile
import slick.jdbc.GetResult

class ProductController @Inject() (dbConfigProvider: DatabaseConfigProvider) extends Controller {
  def searchProducts = Action { request =>
    val dbConfig = dbConfigProvider.get[JdbcProfile]
    val products = for {
      product <- dbConfig.db.run(sql"SELECT * FROM products WHERE ${buildWhereClause(request.queryString)}".as[Product])
